class Compound:
    def __init__(self, name):
        self.name = name

class Reaction:
    def __init__(self, compounds):
        self.compounds = compounds

def reaction_charge(reaction, compound_charge):
    net_charge = 0.0
    absolute_charge = 0.0
    for compound, coeff in reaction.compounds:
        charge = compound_charge.get(compound.name, float('nan'))
        net_charge += charge * float(coeff)
        absolute_charge += abs(charge * float(coeff))
    return {'net_charge': net_charge, 'absolute_charge': absolute_charge}

def main():
    h_plus = Compound('H+')
    oh_minus = Compound('OH-')
    na_plus = Compound('Na+')
    reaction1 = Reaction([
        (h_plus, 2),
        (oh_minus, 1)
    ])
    compound_charge = {
        'H+': 1.0,
        'OH-': -1.0,
        'Na+': 1.0
    }
    net_charge1 = reaction_charge(reaction1, compound_charge)
    print(f"Net charge of reaction1: {net_charge1}")
    reaction2 = Reaction([
        (na_plus, 1),
        (oh_minus, 1)
    ])
    net_charge2 = reaction_charge(reaction2, compound_charge)
    print(f"Net charge of reaction2: {net_charge2}")

if __name__ == '__main__':
    main()
